<script setup lang="ts">import { reactive,ref } from 'vue'; import { useRoute,useRouter } from 'vue-router'; import { ElMessage } from 'element-plus'; import { useAuthStore } from '@/stores/auth'; import { messageOf } from '@/api/http'; const form=reactive({username:'',password:''}),loading=ref(false),auth=useAuthStore(),router=useRouter(),route=useRoute(); async function submit(){loading.value=true;try{await auth.login(form.username,form.password);router.replace(String(route.query.redirect||'/admin/videos'))}catch(e){ElMessage.error(messageOf(e))}finally{loading.value=false}}</script>
<template><div class="login"><el-card shadow="never"><h1>视频管理</h1><el-form :model="form" @submit.prevent="submit"><el-form-item><el-input v-model="form.username" placeholder="用户名" size="large" autofocus/></el-form-item><el-form-item><el-input v-model="form.password" type="password" show-password placeholder="密码" size="large" @keyup.enter="submit"/></el-form-item><el-button type="primary" size="large" :loading="loading" style="width:100%" @click="submit">登录</el-button></el-form></el-card></div></template>
<style scoped>.login{min-height:100vh;display:grid;place-items:center;padding:20px;background:#f5f7fa}.el-card{width:min(380px,100%);border:0;border-radius:12px}.el-card :deep(.el-card__body){padding:34px}h1{font-size:22px;text-align:center;margin:0 0 28px}</style>
